use rayon::prelude::*;

fn main() {
    let numbers: Vec<u64> = (0..1_000_000).collect();

    // Sequential sum
    let seq_sum: u64 = numbers.iter().sum();

    // Parallel sum -- just change iter() to par_iter()
    let par_sum: u64 = numbers.par_iter().sum();

    assert_eq!(seq_sum, par_sum);
    println!("Sum: {}", par_sum);

    // Parallel map + filter
    let results: Vec<u64> = numbers
        .par_iter()
        .filter(|&&x| x % 2 == 0)
        .map(|&x| x * x)
        .collect();

    println!("Even squares count: {}", results.len());
}

