use rayon::prelude::*;

let files = vec!["a.txt", "b.txt", "c.txt"];
let contents: Vec<_> = files
    .par_iter()
    .map(|f| std::fs::read_to_string(f).unwrap_or_default())
    .collect();

use rayon::prelude::*;

let mut data = vec![5, 2, 8, 1, 9, 3];
data.par_sort();           // parallel sort
data.par_sort_unstable();  // parallel unstable sort (faster)

use rayon::prelude::*;

let words = vec!["hello", "world", "foo", "bar", "baz"];

let longest = words
    .par_iter()
    .reduce(|| &"", |a, b| if a.len() >= b.len() { a } else { b });

println!("Longest: {}", longest);

use rayon::ThreadPoolBuilder;

let pool = ThreadPoolBuilder::new()
    .num_threads(4)
    .build()
    .unwrap();

pool.install(|| {
    // All rayon operations in here use this 4-thread pool
    let sum: u64 = (0..1000u64).into_par_iter().sum();
    println!("Sum: {}", sum);
});
